class MutableKey:
    def __init__(self, k):
        self.k = k
    def __hash__(self):
        return hash(self.k)
    def __eq__(self, o):
        return isinstance(o, MutableKey) and self.k == o.k

m = MutableKey("A")
d = {m: 1}
m.k = "B"
print("BUG lookup after mutate", d.get(m))

