from typing import Protocol

class Scorer(Protocol):
    def score(self, pair: tuple[str, str]) -> float: ...

class FakeScorer:
    def score(self, pair: tuple[str, str]) -> float:
        return 1.0 if pair[0] == pair[1] else 0.2

print(FakeScorer().score(("A", "A")))

def apply(norm, text):
    return norm(text)

def strip_norm(s):
    return s.strip()

def casefold_norm(s):
    return s.casefold()

print(apply(strip_norm, "  Hola "))
print(apply(casefold_norm, "HOLA"))

